import{_ as l,C as s,o as r,c as i,a7 as e,E as n}from"./chunks/framework.C5fSpjcB.js";const m=JSON.parse('{"title":"運命の輪（Wheels of Destiny）概要","description":"","frontmatter":{},"headers":[],"relativePath":"ja/wheels/index.md","filePath":"ja/wheels/index.md","lastUpdated":1775394001000}'),o={name:"ja/wheels/index.md"};function d(h,t,c,_,p,f){const a=s("WheelList");return r(),i("div",null,[t[0]||(t[0]=e('<h1 id="運命の輪-wheels-of-destiny-概要" tabindex="-1">運命の輪（Wheels of Destiny）概要 <a class="header-anchor" href="#運命の輪-wheels-of-destiny-概要" aria-label="Permalink to &quot;運命の輪（Wheels of Destiny）概要&quot;">​</a></h1><p><strong>運命の輪</strong>は覚醒体専用の装備システムです。各覚醒体に対応した運命の輪を装備することで、ステータスの強化や特殊効果を得られます。</p><h2 id="基本情報" tabindex="-1">基本情報 <a class="header-anchor" href="#基本情報" aria-label="Permalink to &quot;基本情報&quot;">​</a></h2><ul><li>各覚醒体には<strong>専用の運命の輪</strong>が存在する</li><li>運命の輪はガチャ（召喚）やイベントで入手可能</li><li>強化・突破により性能が向上する</li></ul><h2 id="レアリティ" tabindex="-1">レアリティ <a class="header-anchor" href="#レアリティ" aria-label="Permalink to &quot;レアリティ&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">レアリティ</th><th style="text-align:left;">特徴</th></tr></thead><tbody><tr><td style="text-align:center;"><span class="rarity-ssr">SSR</span></td><td style="text-align:left;">専用パッシブ効果あり。最高性能</td></tr><tr><td style="text-align:center;"><span class="rarity-sr">SR</span></td><td style="text-align:left;">汎用性が高く実用的</td></tr><tr><td style="text-align:center;"><span class="rarity-r">R</span></td><td style="text-align:left;">基本的な性能。繋ぎとして使用</td></tr></tbody></table><h2 id="運命の輪の効果" tabindex="-1">運命の輪の効果 <a class="header-anchor" href="#運命の輪の効果" aria-label="Permalink to &quot;運命の輪の効果&quot;">​</a></h2><ul><li><strong>基礎ステータス上昇</strong> — HP・攻撃力・防御力等のステータスボーナス</li><li><strong>専用パッシブ</strong> — SSR運命の輪のみ。覚醒体固有の特殊効果を付与</li><li><strong>界域ボーナス</strong> — 同界域の運命の輪を装備することで追加ボーナス</li></ul><h2 id="強化方法" tabindex="-1">強化方法 <a class="header-anchor" href="#強化方法" aria-label="Permalink to &quot;強化方法&quot;">​</a></h2><p><em>準備中...</em></p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>SSR運命の輪の専用パッシブは覚醒体の性能を大きく変える場合があります。入手できた場合は優先的に強化しましょう。</p></div><h2 id="運命の輪一覧" tabindex="-1">運命の輪一覧 <a class="header-anchor" href="#運命の輪一覧" aria-label="Permalink to &quot;運命の輪一覧&quot;">​</a></h2>',12)),n(a),t[1]||(t[1]=e('<h2 id="関連ページ" tabindex="-1">関連ページ <a class="header-anchor" href="#関連ページ" aria-label="Permalink to &quot;関連ページ&quot;">​</a></h2><ul><li><a href="./list.html">運命の輪一覧</a></li><li><a href="./../awakeners/">覚醒体図鑑</a></li><li><a href="./../awakeners/leveling.html">育成ガイド</a></li><li><a href="./../covenants/">密契概要</a></li></ul>',2))])}const x=l(o,[["render",d]]);export{m as __pageData,x as default};
